// components/admin/BlogManage.js
import React, { useState, useEffect } from "react";
import axios from "axios";

const BlogManage = () => {
  const [title, setTitle] = useState("");
  const [blogs, setBlogs] = useState([]);

  const fetchBlogs = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/blogs");
      setBlogs(res.data);
    } catch (err) {
      console.error("Error fetching blogs", err);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/api/blogs", {
        title,
        content: "Demo content", // You can extend this as needed
        user_id: 1, // Change according to your backend logic
        category_id: 1,
      });
      setTitle("");
      fetchBlogs();
    } catch (err) {
      console.error("Error adding blog", err);
    }
  };

  useEffect(() => {
    fetchBlogs();
  }, []);

  return (
    <div>
      <h2 className="text-xl font-bold mb-4">Blog Management</h2>

      <form onSubmit={handleSubmit} className="mb-6">
        <div className="flex items-center space-x-4">
          <input
            type="text"
            placeholder="Enter blog title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className="p-2 border border-gray-300 rounded w-1/2"
          />
          <button
            type="submit"
            className="bg-green-600 text-white px-4 py-2 rounded"
          >
            Add Blog
          </button>
        </div>
      </form>

      <table className="w-full table-auto border border-gray-300 bg-white">
        <thead>
          <tr className="bg-gray-200">
            <th className="p-2 border">ID</th>
            <th className="p-2 border">Title</th>
          </tr>
        </thead>
        <tbody>
          {blogs.map((blog) => (
            <tr key={blog.id}>
              <td className="p-2 border text-center">{blog.id}</td>
              <td className="p-2 border">{blog.title}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default BlogManage;
